#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
const int INF = 0x3f3f3f3f;
int m,n,sum,Mxflow;
int St,Ed,dis[N];queue<int> q;
int tot=1,head[N],to[N],wei[N],nxt[N];
int read() {
	static char ch;static int su;
	if(ch=='\n'){ch=0;return -1;}
	while(ch<'0'||ch>'9')ch=getchar();
	su=0;while(ch>='0'&&ch<='9')
		su=su*10+ch-'0',ch=getchar();return su;
}
void Add_edge(int x,int y,int z){
    ++tot,to[tot]=y,wei[tot]=z;
    nxt[tot]=head[x],head[x]=tot;
    ++tot,to[tot]=x,wei[tot]=0;
    nxt[tot]=head[y],head[y]=tot;return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=head[u];i;i=nxt[i]){
            int v=to[i],w=wei[i];
            if(!w||dis[v])continue;
            dis[v]=dis[u]+1;
            if(v==Ed)return 1;q.push(v);
        }
    }return 0;
}
int DFS_Cntflow(int u,int flow){
    if(u==Ed)return flow;int now=flow;
    for(int i=head[u];i;i=nxt[i]){
        if(now<=0)break;
        int v=to[i],w=wei[i];
        if(!w||dis[v]!=dis[u]+1)continue;
        int tmp=DFS_Cntflow(v,min(now,w));
        if(!tmp)dis[v]=0;
        else wei[i]-=tmp,wei[i^1]+=tmp,now-=tmp;
    }return flow-now;
}
int Sol_Dinic(){
    int res=0,flow=0;
    while(BFS_Canit())
        while(flow=DFS_Cntflow(St,INF))res+=flow;
    return res;
}
int main(){
    scanf("%d %d",&m,&n);
    St=m+n+1,Ed=St+1;
    for(int i=1,x;i<=m;i++){
        scanf("%d",&x);sum+=x;
        Add_edge(St,i,x);
        while(~(x=read()))Add_edge(i,m+x,INF);
    }for(int i=1,x;i<=n;i++)
        scanf("%d",&x),Add_edge(m+i,Ed,x);
    Mxflow=Sol_Dinic();
    for(int i=1;i<=m;i++)
        if(dis[i])cout<<i<<" ";cout<<"\n";
    for(int i=1;i<=n;i++)
        if(dis[m+i])cout<<i<<" ";cout<<"\n";
    cout<<sum-Mxflow<<"\n";
    return 0;
}
